package com.samudhra.certificates.exception;
import com.samudhra.certificates.dto.ApiResponse; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import org.springframework.web.bind.MethodArgumentNotValidException; import java.util.*;
@RestControllerAdvice public class ApiExceptionHandler { @ExceptionHandler(NoSuchElementException.class) @ResponseStatus(HttpStatus.NOT_FOUND) ApiResponse<Void> notFound(NoSuchElementException e){return ApiResponse.error(e.getMessage());} @ExceptionHandler({IllegalArgumentException.class,MethodArgumentNotValidException.class}) @ResponseStatus(HttpStatus.BAD_REQUEST) ApiResponse<Void> invalid(Exception e){return ApiResponse.error(e.getMessage());} @ExceptionHandler(Exception.class) @ResponseStatus(HttpStatus.INTERNAL_SERVER_ERROR) ApiResponse<Void> unknown(Exception e){e.printStackTrace(); return ApiResponse.error("An unexpected server error occurred: " + e.getMessage());} }
